// Validate input and prepare project data
const projectName = $input.body.project_name;
const ownerEmail = $input.body.owner_email;
const description = $input.body.description || '';
const industry = $input.body.industry || '';
const ideaDescription = $input.body.idea_description;

// Validate required fields
const errors = [];
if (!projectName || projectName.trim() === '') {
  errors.push('project_name is required');
}
if (!ownerEmail || ownerEmail.trim() === '') {
  errors.push('owner_email is required');
}
if (!ideaDescription || ideaDescription.trim() === '') {
  errors.push('idea_description is required');
}

if (errors.length > 0) {
  throw new Error('Validation failed: ' + errors.join(', '));
}

// Generate project_id: slugified name + timestamp
const slug = projectName
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .substring(0, 50);
const timestamp = Math.floor(Date.now() / 1000);
const projectId = slug + '-' + timestamp;

return {
  project_id: projectId,
  project_name: projectName,
  owner_email: ownerEmail,
  description: description,
  industry: industry,
  idea_description: ideaDescription,
  created_date: new Date().toISOString()
};

// Create sub-folders in the newly created Google Drive folder
const parentFolderId = $input.first().json.id;
const subFolders = ['Analyses', 'Research', 'PRD', 'Handoff'];

// Build request items for parallel Google Drive API calls
const folderStructure = {
  parent_folder_id: parentFolderId,
  sub_folders: {}
};

return {
  parent_folder_id: parentFolderId,
  sub_folders: subFolders,
  folder_structure: folderStructure
};

// Prepare email body with project details
const projectId = $input.first().json.project_id;
const projectName = $input.first().json.project_name;
const ownerEmail = $input.first().json.owner_email;
const folderId = $input.last().json.parent_folder_id || '';
const driveLink = 'https://drive.google.com/drive/folders/' + folderId;

return {
  to: ownerEmail,
  subject: 'My Product Agent: Project Created - ' + projectName,
  html: '<h2>Project Created Successfully</h2>' +
        '<p><strong>Project ID:</strong> ' + projectId + '</p>' +
        '<p><strong>Project Name:</strong> ' + projectName + '</p>' +
        '<p><strong>Status:</strong> Created - Ready for Stage 2</p>' +
        '<p><a href="' + driveLink + '">View Project Folder in Google Drive</a></p>' +
        '<p>Your project has been registered in the Master Pipeline and is ready for the next stage.</p>',
  projectId: projectId,
  projectName: projectName,
  folderId: folderId
};

// Build success response
const projectId = $input.first().json.project_id;
const projectName = $input.first().json.project_name;
const folderId = $input.first().json.parent_folder_id || '';
const googleFolderUrl = 'https://drive.google.com/drive/folders/' + folderId;

return {
  success: true,
  project_id: projectId,
  project_name: projectName,
  google_folder_url: googleFolderUrl,
  message: 'Project created successfully. Confirmation email sent to owner.'
};

// Handle validation error
const errorMessage = $input.first().json.message || 'Validation failed';
return {
  success: false,
  error: errorMessage,
  code: 'VALIDATION_ERROR'
};
